+    fn make_env(term: &str, term_program: &str, colorterm: &str) -> DetectInputs {
+        DetectInputs {
+            no_color: false,
+            term: term.to_string(),
+            term_program: term_program.to_string(),
+            colorterm: colorterm.to_string(),
+            in_tmux: false,
+            in_screen: false,
+            in_zellij: false,
+            kitty_window_id: false,
+            wt_session: false,
+        }
+    }
