+    // ====== Wide character visual column handling ======
+
+    #[test]
+    fn wide_char_visual_col() {
+        // CJK characters are 2 cells wide
+        let r = rope("\u{4E16}\u{754C}"); // "世界"
+        let nav = CursorNavigator::new(&r);
+        let pos0 = nav.from_line_grapheme(0, 0);
